/// <summary>
///
/// </summary>
/// <param name = "_this"></param>
/// <returns></returns>
[SysClientCacheDataMethodAttribute(true)]
public static display DimensionValue businessUnit(GeneralJournalAccountEntry _this)
{
    DimensionValue businessUnitValue;
    str businessUnitStr = "BusinessUnit";
    DimensionAttributeValueSetStorage dimStorage;

    dimStorage = DimensionAttributeValueSetStorage::find(_this.LedgerDimension);
    businessUnitValue = dimStorage.getDisplayValueByDimensionAttribute(DimensionAttribute::findByName(businessUnitStr).RecId);

    return businessUnitValue;
}

